/* ─────────────────────────────────────────────
   HELPERS
───────────────────────────────────────────── */
function extractYouTubeId(url: string): string | null {
  try {
    const u = new URL(url);
    if (u.hostname.includes("youtu.be")) return u.pathname.slice(1).split("?")[0];
    if (u.hostname.includes("youtube.com")) return u.searchParams.get("v");
    return null;
  } catch {
    return null;
  }
}

function looksLikeLink(value?: string) {
  const text = String(value || "").trim().toLowerCase();
  if (!text) return false;
  return (
    text.startsWith("http://") ||
    text.startsWith("https://") ||
    text.includes("youtube.com") ||
    text.includes("youtu.be") ||
    text.includes("watch?v=") ||
    text.includes("playlist=") ||
    text.includes("www.")
  );
}

function normalizeText(value?: string) {
  return String(value || "")
    .replace(/\r/g, "")
    .replace(/\t/g, " ")
    .replace(/\u00a0/g, " ")
    .replace(/\n{3,}/g, "\n\n")
    .trim();
}

function safeText(value: string | undefined, fallback: string) {
  const cleaned = normalizeText(value);
  if (!cleaned) return fallback;
  if (looksLikeLink(cleaned)) return fallback;
  return cleaned;
}

function sanitizeCaption(value: string | undefined, musicUrl?: string) {
  const cleaned = normalizeText(value);
  if (!cleaned) return "";
  if (looksLikeLink(cleaned)) return "";
  if (musicUrl && cleaned === normalizeText(musicUrl)) return "";
  return cleaned;
}


function stripLeadingSalutation(value: string, names: string[]) {
  const cleaned = normalizeText(value);
  if (!cleaned) return cleaned;

  for (const rawName of names.map((name) => normalizeText(name)).filter(Boolean)) {
    if (cleaned.toLowerCase().startsWith(rawName.toLowerCase())) {
      let rest = cleaned.slice(rawName.length).trimStart();
      rest = rest.replace(/^[,:;.!¡!¿?~-]+/, "").trimStart();
      return rest || cleaned;
    }
  }

  return cleaned;
}

function getSlugFromPathname() {
  if (typeof window === "undefined") return "";
  const parts = window.location.pathname.split("/").filter(Boolean);
  return decodeURIComponent(parts[parts.length - 1] || "");
}

function hasUsefulPreviewData(value: RomanticLetterData | null | undefined) {
  if (!value) return false;
  return Boolean(
    normalizeText(value.recipientName) ||
      normalizeText(value.senderName) ||
      normalizeText(value.nickname) ||
      normalizeText(value.message) ||
      normalizeText(value.letterMessage) ||
      normalizeText(value.shortMessage) ||
      normalizeText(value.finalMessage) ||
      normalizeText(value.relationshipStartDate) ||
      normalizeText(value.coverPhotoUrl) ||
      normalizeText(value.musicUrl) ||
      (Array.isArray(value.photoUrls) && value.photoUrls.some((item) => Boolean(normalizeText(item)))) ||
      (Array.isArray(value.photoCaptions) && value.photoCaptions.some((item) => Boolean(normalizeText(item))))
  );
}

function readStoredPreviewFromSession(expectedSlug?: string): RomanticLetterData | null {
  if (typeof window === "undefined") return null;

  const rawGeneric = window.sessionStorage.getItem(PREVIEW_STORAGE_KEY);
  if (!rawGeneric) return null;

  try {
    const parsed = JSON.parse(rawGeneric) as RomanticLetterData | { slug?: string } | null;
    if (!parsed) return null;

    const candidate = parsed as RomanticLetterData;
    if (!hasUsefulPreviewData(candidate)) return null;

    const sessionSlug = normalizeText(candidate.slug);
    if (expectedSlug && sessionSlug && sessionSlug !== expectedSlug) {
      return candidate;
    }

    return candidate;
  } catch {
    return null;
  }
}

function openMomentiaPreviewDb(): Promise<IDBDatabase> {
  return new Promise((resolve, reject) => {
    if (typeof window === "undefined" || !window.indexedDB) {
      reject(new Error("IndexedDB no disponible"));
      return;
    }

    const request = window.indexedDB.open(PREVIEW_DB_NAME, 1);
    request.onupgradeneeded = () => {
      const db = request.result;
      if (!db.objectStoreNames.contains(PREVIEW_DB_STORE)) {
        db.createObjectStore(PREVIEW_DB_STORE);
      }
    };
    request.onsuccess = () => resolve(request.result);
    request.onerror = () => reject(request.error || new Error("No se pudo abrir IndexedDB"));
  });
}

async function readStoredPreview(): Promise<RomanticLetterData | null> {
  if (typeof window === "undefined") return null;

  const slug = getSlugFromPathname();

  const fromSession = readStoredPreviewFromSession(slug);
  if (fromSession) return fromSession;

  try {
    const db = await openMomentiaPreviewDb();
    const result = await new Promise<RomanticLetterData | null>((resolve, reject) => {
      const tx = db.transaction(PREVIEW_DB_STORE, "readonly");
      const store = tx.objectStore(PREVIEW_DB_STORE);
      const request = store.get(slug || "latest");
      request.onsuccess = () => resolve((request.result as RomanticLetterData | undefined) || null);
      request.onerror = () => reject(request.error || new Error("No se pudo leer la vista previa"));
      tx.oncomplete = () => db.close();
    });
    if (hasUsefulPreviewData(result)) return result;
  } catch {
    // fallback below
  }

  return readStoredPreviewFromSession();
}

function buildYouTubeEmbed(url: string) {
  const id = extractYouTubeId(url);
  if (!id) return "";

  const origin = typeof window !== "undefined" ? encodeURIComponent(window.location.origin) : "";
  return `https://www.youtube-nocookie.com/embed/${id}?autoplay=1&loop=1&playlist=${id}&controls=0&modestbranding=1&rel=0&playsinline=1&enablejsapi=1${origin ? `&origin=${origin}` : ""}`;
}

function getSongLabel(url: string) {
  const cleaned = normalizeText(url);
  if (!cleaned) return "";
  const id = extractYouTubeId(cleaned);
  if (!id) return "";
  return `YouTube · ${id.slice(0, 8)}`;
}

/* ─────────────────────────────────────────────
   TYPEWRITER HOOK
───────────────────────────────────────────── */
function useTypewriter(text: string, speed = 78) {
  const [displayed, setDisplayed] = useState("");
  const [done, setDone] = useState(false);

  useEffect(() => {
    setDisplayed("");
    setDone(false);
    if (!text) return;

    let i = 0;
    const id = window.setInterval(() => {
      i += 1;
      setDisplayed(text.slice(0, i));
      if (i >= text.length) {
        window.clearInterval(id);
        setDone(true);
      }
    }, speed);

    return () => window.clearInterval(id);
  }, [text, speed]);

  return { text: displayed, done };
}

