function GoldQuill({ x, y, size = 98 }: { x: number; y: number; size?: number }) {
  return (
    <img
      src={QUILL_PNG}
      alt=""
      aria-hidden="true"
      style={{
        position: "absolute",
        left: x - size * 0.36,
        top: y - size * 0.9,
        width: size,
        height: size * 1.02,
        objectFit: "contain",
        transform: "rotate(-12deg)",
        pointerEvents: "none",
        zIndex: 14,
        filter: "drop-shadow(0 10px 18px rgba(55,30,10,0.32))",
        transition: "none",
        userSelect: "none",
      }}
    />
  );
}

function InkParticles({ x, y, seed }: { x: number; y: number; seed: number }) {
  const particles = useMemo(
    () =>
      Array.from({ length: 12 }, (_, i) => ({
        dx: (i - 6) * 5,
        dy: -8 - (i % 4) * 7,
        size: 4 + (i % 3) * 2,
        delay: `${i * 0.024}s`,
        glyph: i % 5 === 0 ? "♥" : i % 2 === 0 ? "✦" : "•",
      })),
    []
  );

  return (
    <div key={seed} style={{ position: "absolute", left: x - 10, top: y - 12, pointerEvents: "none", zIndex: 13 }}>
      {particles.map((p, i) => (
        <span
          key={i}
          style={{
            position: "absolute",
            fontSize: p.glyph === "•" ? p.size : p.size + 2,
            lineHeight: 1,
            color:
              p.glyph === "♥"
                ? "rgba(255, 211, 231, 0.96)"
                : i % 2 === 0
                ? "rgba(255, 226, 141, 0.96)"
                : "rgba(255, 245, 208, 0.92)",
            textShadow: "0 0 14px rgba(255, 204, 102, 0.5)",
            animation: `romInkSpark 0.6s ease-out ${p.delay} both`,
            transform: `translate(${p.dx}px, ${p.dy}px)`,
            filter: "drop-shadow(0 0 8px rgba(255,214,120,0.4))",
          }}
        >
          {p.glyph}
        </span>
      ))}
    </div>
  );
}

function WritingStage({
  text,
  done,
  variant,
}: {
  text: string;
  done: boolean;
  variant: "intro" | "letter";
}) {
  const containerRef = useRef<HTMLDivElement>(null);
  const lastCharRef = useRef<HTMLSpanElement>(null);
  const [quillXY, setQuillXY] = useState({ x: 38, y: 52 });
  const [sparkSeed, setSparkSeed] = useState(0);

  useLayoutEffect(() => {
    if (!containerRef.current || !lastCharRef.current) return;
    const parentRect = containerRef.current.getBoundingClientRect();
    const charRect = lastCharRef.current.getBoundingClientRect();
    setQuillXY({
      x: charRect.left - parentRect.left + Math.max(charRect.width * 0.74, 12),
      y: charRect.top - parentRect.top + Math.max(charRect.height * 0.12, 0),
    });
  }, [text]);

  useEffect(() => {
    if (!text) return;
    setSparkSeed((prev) => prev + 1);
  }, [text.length]);

  const chars = text.split("");

  const textStyle: React.CSSProperties =
    variant === "intro"
      ? {
          fontFamily: "'Cormorant Garamond', serif",
          fontStyle: "italic",
          fontWeight: 600,
          fontSize: "clamp(2rem, 4.5vw, 3.2rem)",
          lineHeight: 1.48,
          color: "rgba(255,242,246,0.97)",
          textShadow: "0 2px 28px rgba(196,98,124,0.22)",
          whiteSpace: "pre-wrap",
          overflowWrap: "anywhere",
        }
      : {
          fontFamily: "'Great Vibes', cursive",
          fontSize: "clamp(1.55rem, 3vw, 2.34rem)",
          lineHeight: 2.02,
          color: "#5b2f1d",
          whiteSpace: "pre-wrap",
          overflowWrap: "anywhere",
        };

  return (
    <div
      ref={containerRef}
      style={{
        position: "relative",
        textAlign: variant === "intro" ? "center" : "left",
        minHeight: variant === "intro" ? 170 : 270,
      }}
    >
      {!done && (
        <>
          <InkParticles x={quillXY.x + 6} y={quillXY.y + 24} seed={sparkSeed} />
          <GoldQuill x={quillXY.x} y={quillXY.y} size={variant === "intro" ? 90 : 82} />
        </>
      )}
      <div style={textStyle}>
        {chars.map((char, i) => {
          const isLast = i === chars.length - 1;
          if (char === "\n") return <br key={i} />;
          return (
            <span key={i} ref={isLast ? lastCharRef : null}>
              {char}
            </span>
          );
        })}
        {!done && <span style={{ animation: "romBlink 1s infinite" }}>|</span>}
      </div>
    </div>
  );
}

